498→/// Encode a column index as a dense character: 1-9 then a-z then A-Z (61 max)
499→fn zjjrpd_commit_index_char(index: usize) -> Option<char> {
500→    match index {
501→        0..=8 => Some((b'1' + index as u8) as char),
502→        9..=34 => Some((b'a' + (index - 9) as u8) as char),
503→        35..=60 => Some((b'A' + (index - 35) as u8) as char),
504→        _ => None,
505→    }
506→}
