624→/// Print files-per-commit bitmap for a single pace.
625→///
626→/// Shows which files each commit in this pace touched.
627→/// Called after tack history in pace parade.
628→fn zjjrpd_print_pace_commits(firemark: &Firemark, coronet_key: &str) {
629→    let rein_args = jjrs_ReinArgs {
630→        firemark: firemark.jjrf_as_str().to_string(),
631→        limit: 10000,
632→    };
633→
634→    let entries = match jjrs_get_entries(&rein_args) {
635→        Ok(e) => e,
636→        Err(e) => {
637→            eprintln!("jjx_show: error getting steeplechase entries: {}", e);
638→            return;
639→        }
640→    };
641→
642→    // Filter by coronet, then reverse for chronological order
643→    let pace_entries: Vec<&jjrs_SteeplechaseEntry> = entries
644→        .iter()
645→        .filter(|e| e.coronet.as_deref() == Some(coronet_key))
646→        .collect::<Vec<_>>()
647→        .into_iter()
648→        .rev()
649→        .collect();
650→
651→    if pace_entries.is_empty() {
652→        return;
653→    }
654→
655→    // Get files for each commit
656→    let num_commits = pace_entries.len();
657→    let mut file_touches: BTreeMap<String, Vec<bool>> = BTreeMap::new();
658→
659→    for (col, entry) in pace_entries.iter().enumerate() {
660→        let files = zjjrq_files_for_commit(&entry.commit);
661→        for path in files {
662→            if zjjrq_is_infra_file(&path) {
663→                continue;
664→            }
665→            let bare = zjjrq_bare_filename(&path);
666→            let row = file_touches.entry(bare).or_insert_with(|| vec![false; num_commits]);
667→            row[col] = true;
668→        }
669→    }
670→
671→    if file_touches.is_empty() {
672→        println!();
673→        println!("Pace commits: (no project file commits)");
674→        return;
675→    }
676→
677→    println!();
678→    println!("Pace commits (x = commit touched file):");
679→    println!();
680→
681→    // Legend: commit index char, SHA, subject
682→    for (i, entry) in pace_entries.iter().enumerate() {
683→        let ch = zjjrpd_commit_index_char(i).unwrap_or('?');
684→        println!("  {} {}  {}", ch, entry.commit, entry.subject);
685→    }
686→    println!();
687→
688→    // Column header line
689→    let header: String = (0..num_commits).filter_map(zjjrpd_commit_index_char).collect();
690→    println!("{}", header);
691→
692→    // Group by identical touch pattern
693→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
694→    for (filename, pattern) in &file_touches {
695→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
696→    }
697→    for files in pattern_groups.values_mut() {
698→        files.sort();
699→    }
700→
701→    // Sort: more touches first, then lexicographic
702→    let mut sorted: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
703→    sorted.sort_by(|(a, _), (b, _)| {
704→        let ca: usize = a.iter().filter(|&&v| v).count();
705→        let cb: usize = b.iter().filter(|&&v| v).count();
706→        cb.cmp(&ca).then_with(|| a.cmp(b))
707→    });
708→
709→    for (pattern, files) in &sorted {
710→        let bits: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
711→        println!("{} {}", bits, files.join(", "));
712→    }
713→}
