147→    pub pace_files: std::collections::BTreeMap<String, std::collections::BTreeSet<String>>,
148→    /// Work files from heat-level (no coronet) commits
149→    pub heat_files: std::collections::BTreeSet<String>,
150→    /// All coronets that have at least one commit
151→    pub coronets_with_commits: std::collections::BTreeSet<String>,
152→}
