 637→/// Build trophy markdown content
 638→fn zjjrg_build_trophy_content(
 639→    firemark_key: &str,
 640→    heat: &jjrg_Heat,
 641→    paddock_content: &str,
 642→    today: &str,
 643→    steeplechase: &[SteeplechaseEntry],
 644→) -> Result<String, String> {
 645→    let mut content = String::new();
 646→
 647→    // Header
 648→    content.push_str(&format!("# Heat Trophy: {}\n\n", heat.silks));
 649→    content.push_str(&format!("**Firemark:** {}\n", firemark_key));
 650→    content.push_str(&format!("**Created:** {}\n", heat.creation_time));
 651→    content.push_str(&format!("**Retired:** {}\n", today));
 652→    content.push_str("**Status:** retired\n\n");
 653→
 654→    // Paddock
 655→    content.push_str("## Paddock\n\n");
 656→    content.push_str(paddock_content);
 657→    if !paddock_content.ends_with('\n') {
 658→        content.push('\n');
 659→    }
 660→    content.push('\n');
 661→
 662→    // Paces (in order)
 663→    content.push_str("## Paces\n\n");
 664→    for coronet_key in &heat.order {
 665→        if let Some(pace) = heat.paces.get(coronet_key) {
 666→            // Get final state from most recent tack
 667→            let final_state = pace.tacks.first()
 668→                .map(|t| match t.state {
 669→                    jjrg_PaceState::Rough => "rough",
 670→                    jjrg_PaceState::Bridled => "bridled",
 671→                    jjrg_PaceState::Complete => "complete",
 672→                    jjrg_PaceState::Abandoned => "abandoned",
 673→                })
 674→                .unwrap_or("unknown");
 675→
 676→            let pace_silks = pace.tacks.first()
 677→                .map(|t| t.silks.as_str())
 678→                .unwrap_or("unknown");
 679→
 680→            content.push_str(&format!(
 681→                "### {} ({}) [{}]\n\n",
 682→                pace_silks, coronet_key, final_state
 683→            ));
 684→
 685→            // Tack history (newest first, as stored)
 686→            for tack in &pace.tacks {
 687→                let state_str = match tack.state {
 688→                    jjrg_PaceState::Rough => "rough",
 689→                    jjrg_PaceState::Bridled => "bridled",
 690→                    jjrg_PaceState::Complete => "complete",
 691→                    jjrg_PaceState::Abandoned => "abandoned",
 692→                };
 693→                content.push_str(&format!("**[{}] {}**\n\n", tack.ts, state_str));
 694→                content.push_str(&tack.text);
 695→                if !tack.text.ends_with('\n') {
 696→                    content.push('\n');
 697→                }
 698→                if let Some(ref direction) = tack.direction {
 699→                    content.push_str(&format!("\n*Direction:* {}\n", direction));
 700→                }
 701→                content.push('\n');
 702→            }
 703→        }
 704→    }
 705→
 706→    // Steeplechase (newest first, as provided)
 707→    content.push_str("## Steeplechase\n\n");
 708→    if steeplechase.is_empty() {
 709→        content.push_str("(no entries)\n\n");
 710→    } else {
 711→        for entry in steeplechase {
 712→            // Format: ### {date} - {coronet or "Heat"} - {action or "notch"}
 713→            let identity = entry.coronet.as_deref().unwrap_or("Heat");
 714→            let action = entry.action.as_deref().unwrap_or("notch");
 715→            content.push_str(&format!(
 716→                "### {} - {} - {}\n\n",
 717→                entry.timestamp, identity, action
 718→            ));
 719→            content.push_str(&entry.subject);
 720→            if !entry.subject.ends_with('\n') {
 721→                content.push('\n');
 722→            }
 723→            content.push('\n');
 724→        }
 725→    }
 726→
 727→    Ok(content)
 728→}
