 730→/// Curry - update Heat paddock with chalk entry
 731→///
 732→/// Writes new paddock content and creates a chalk commit recording the change.
 733→pub fn jjrg_curry(
 734→    gallops_path: &std::path::Path,
 735→    firemark: &Firemark,
 736→    new_content: &str,
 737→    note: Option<&str>,
 738→) -> Result<(), String> {
 739→    use std::fs;
 740→
 741→    // Load gallops
 742→    let gallops = jjrg_Gallops::jjrg_load(gallops_path)
 743→        .map_err(|e| format!("Failed to load Gallops: {}", e))?;
 744→
 745→    // Verify heat exists
 746→    let firemark_key = firemark.jjrf_display();
 747→    let heat = gallops.heats.get(&firemark_key)
 748→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
 749→
 750→    // Write new paddock content
 751→    let paddock_path = std::path::Path::new(&heat.paddock_file);
 752→    fs::write(paddock_path, new_content)
 753→        .map_err(|e| format!("Failed to write paddock file: {}", e))?;
 754→
 755→    // Build chalk message
 756→    let description = if let Some(n) = note {
 757→        format!("paddock curried: {}", n)
 758→    } else {
 759→        "paddock curried".to_string()
 760→    };
 761→
 762→    // Create chalk commit using vvc
 763→    use crate::jjrn_notch::jjrn_format_heat_discussion;
 764→    let message = jjrn_format_heat_discussion(firemark, &description);
 765→
 766→    let commit_args = vvc::vvcm_CommitArgs {
 767→        files: vec![paddock_path.to_string_lossy().to_string()],
 768→        message,
 769→        size_limit: vvc::VVCG_SIZE_LIMIT,
 770→        warn_limit: vvc::VVCG_WARN_LIMIT,
 771→    };
 772→
 773→    // Acquire lock for commit
 774→    let lock = vvc::vvcc_CommitLock::vvcc_acquire()
 775→        .map_err(|e| format!("Failed to acquire commit lock: {}", e))?;
 776→
 777→    match vvc::machine_commit(&lock, &commit_args) {
 778→        Ok(hash) => {
 779→            eprintln!("jjx_curry: committed {}", &hash[..8]);
 780→            Ok(())
 781→        }
 782→        Err(e) => Err(format!("Commit failed: {}", e)),
 783→    }
 784→    // lock released here
 785→}
 786→
 787→/// Furlough a Heat - change status or rename
 788→///
 789→/// Updates heat status (racing/stabled) and/or silks.
 790→/// At least one change must be requested.
 791→pub fn jjrg_furlough(gallops: &mut jjrg_Gallops, args: jjrg_FurloughArgs) -> Result<(), String> {
 792→    // Validate at least one option provided
 793→    if !args.racing && !args.stabled && args.silks.is_none() {
 794→        return Err("At least one option required: --racing, --stabled, or --silks".to_string());
 795→    }
 796→
 797→    // Validate racing/stabled mutual exclusivity
 798→    if args.racing && args.stabled {
 799→        return Err("Cannot specify both --racing and --stabled".to_string());
 800→    }
 801→
 802→    // Validate silks if provided
 803→    if let Some(ref silks) = args.silks {
 804→        if !zjjrg_is_kebab_case(silks) {
 805→            return Err(format!("silks must be non-empty alphanumeric-kebab (letters, digits, hyphens), got '{}'", silks));
 806→        }
 807→    }
 808→
 809→    // Parse and normalize firemark
 810→    let firemark = Firemark::jjrf_parse(&args.firemark)
 811→        .map_err(|e| format!("Invalid firemark: {}", e))?;
 812→    let firemark_key = firemark.jjrf_display();
 813→
 814→    // Verify Heat exists and check status
 815→    {
 816→        let heat = gallops.heats.get(&firemark_key)
 817→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
 818→
 819→        // Check not retired (terminal state)
 820→        if heat.status == jjrg_HeatStatus::Retired {
 821→            return Err(format!("Heat '{}' is retired (terminal state)", firemark_key));
 822→        }
 823→
 824→        // Note: requesting the same status is allowed — it promotes the heat
 825→        // to the top of its list (racing or stabled) for reordering purposes.
 826→    }
 827→
 828→    // Apply status change if requested — also promotes heat to top of list
 829→    if args.racing {
 830→        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Racing;
 831→        if let Some(heat_entry) = gallops.heats.shift_remove(&firemark_key) {
 832→            gallops.heats.shift_insert(0, firemark_key.clone(), heat_entry);
 833→        }
 834→    } else if args.stabled {
 835→        gallops.heats.get_mut(&firemark_key).unwrap().status = jjrg_HeatStatus::Stabled;
 836→        if let Some(heat_entry) = gallops.heats.shift_remove(&firemark_key) {
 837→            gallops.heats.shift_insert(0, firemark_key.clone(), heat_entry);
 838→        }
 839→    }
 840→
 841→    // Apply silks change if requested
 842→    if let Some(silks) = args.silks {
 843→        gallops.heats.get_mut(&firemark_key).unwrap().silks = silks;
 844→    }
 845→
 846→    Ok(())
 847→}
 848→
 849→/// Garland a Heat - celebrate completion and create continuation
 850→///
 851→/// Updates source heat silks to garlanded form and status to stabled.
 852→/// Creates new heat with continuation silks, status racing.
 853→/// Transfers actionable paces (rough/bridled) to new heat.
 854→/// Retains complete/abandoned paces in garlanded heat.
 855→pub fn jjrg_garland(gallops: &mut jjrg_Gallops, args: jjrg_GarlandArgs, base_path: &Path) -> Result<jjrg_GarlandResult, String> {
 856→    use crate::jjrc_core::jjrc_timestamp_from_env;
 857→    use crate::jjrq_query::{jjrq_parse_silks_sequence, jjrq_build_garlanded_silks, jjrq_build_continuation_silks};
 858→
 859→    // Parse and normalize firemark
 860→    let firemark = Firemark::jjrf_parse(&args.firemark)
 861→        .map_err(|e| format!("Invalid firemark: {}", e))?;
 862→    let firemark_key = firemark.jjrf_display();
 863→
 864→    // Verify source heat exists and extract needed data (avoid holding the borrow)
 865→    let (source_silks, source_paddock_file, source_order, actionable_count, retained_count) = {
 866→        let source_heat = gallops.heats.get(&firemark_key)
 867→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
 868→
 869→        // Parse source silks to determine sequence
 870→        let (base, sequence) = jjrq_parse_silks_sequence(&source_heat.silks);
 871→        let seq = sequence.unwrap_or(1);
 872→
 873→        // Count actionable paces
 874→        let actionable_count = source_heat.order.iter().filter(|coronet_key| {
 875→            if let Some(pace) = source_heat.paces.get(*coronet_key) {
 876→                if let Some(tack) = pace.tacks.first() {
 877→                    matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled)
 878→                } else {
 879→                    false
 880→                }
 881→            } else {
 882→                false
 883→            }
 884→        }).count();
 885→
 886→        // Validate there are actionable paces to transfer
 887→        if actionable_count == 0 {
 888→            return Err(format!("Heat '{}' has no actionable paces to transfer", firemark_key));
 889→        }
 890→
 891→        // Count retained paces
 892→        let retained_count = source_heat.paces.len() - actionable_count;
 893→
 894→        // Count complete paces for steeplechase marker
 895→        let complete_count = source_heat.order.iter().filter(|coronet_key| {
 896→            if let Some(pace) = source_heat.paces.get(*coronet_key) {
 897→                if let Some(tack) = pace.tacks.first() {
 898→                    tack.state == jjrg_PaceState::Complete
 899→                } else {
 900→                    false
 901→                }
 902→            } else {
 903→                false
 904→            }
 905→        }).count();
 906→
 907→        // Create steeplechase marker entry
 908→        let marker_text = format!("Garlanded at pace {} — magnificent service", complete_count);
 909→
 910→        // Update source heat: add steeplechase marker (prepend to paddock file)
 911→        let source_paddock_path = base_path.join(&source_heat.paddock_file);
 912→        let existing_content = std::fs::read_to_string(&source_paddock_path)
 913→            .map_err(|e| format!("Failed to read paddock file: {}", e))?;
 914→
 915→        let updated_content = format!("{}\n\n{}", marker_text, existing_content);
 916→        std::fs::write(&source_paddock_path, updated_content)
 917→            .map_err(|e| format!("Failed to write paddock file: {}", e))?;
 918→
 919→        ((base, seq), source_heat.paddock_file.clone(), source_heat.order.clone(), actionable_count, retained_count)
 920→    };
 921→
 922→    // Build garlanded and continuation silks
 923→    let (base, seq) = source_silks;
 924→    let garlanded_silks = jjrq_build_garlanded_silks(&base, seq);
 925→    let continuation_silks = jjrq_build_continuation_silks(&base, seq + 1);
 926→
 927→    // Nominate new heat with continuation silks
 928→    let created_ts = jjrc_timestamp_from_env();
 929→    let nominate_args = jjrg_NominateArgs {
 930→        silks: continuation_silks.clone(),
 931→        created: created_ts,
 932→    };
 933→    let nominate_result = jjrg_nominate(gallops, nominate_args, base_path)?;
 934→    let new_firemark_key = nominate_result.firemark.clone();
 935→
 936→    // Get destination heat paddock file for copy
 937→    let dest_paddock_file = {
 938→        let dest_heat = gallops.heats.get(&new_firemark_key)
 939→            .ok_or_else(|| "Failed to retrieve newly nominated heat".to_string())?;
 940→        dest_heat.paddock_file.clone()
 941→    };
 942→
 943→    // Read original paddock content before modifications (for new heat)
 944→    let source_paddock_path = base_path.join(&source_paddock_file);
 945→    let original_paddock_content = std::fs::read_to_string(&source_paddock_path)
 946→        .map_err(|e| format!("Failed to read paddock file: {}", e))?;
 947→
 948→    // Extract original content (removing marker we just added)
 949→    let existing_content = original_paddock_content.split_once("\n\n")
 950→        .map(|(_, rest)| rest)
 951→        .unwrap_or(&original_paddock_content);
 952→
 953→    // Copy paddock content from source to new heat
 954→    let dest_paddock_path = base_path.join(&dest_paddock_file);
 955→    std::fs::write(&dest_paddock_path, existing_content)
 956→        .map_err(|e| format!("Failed to copy paddock to new heat: {}", e))?;
 957→
 958→    // Draft all actionable paces to new heat (in order)
 959→    for coronet_key in source_order {
 960→        if let Some(pace) = gallops.heats.get(&firemark_key).unwrap().paces.get(&coronet_key) {
 961→            if let Some(tack) = pace.tacks.first() {
 962→                if matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled) {
 963→                    // Draft this pace to new heat (append to end)
 964→                    let draft_args = jjrg_DraftArgs {
 965→                        coronet: coronet_key.clone(),
 966→                        to: new_firemark_key.clone(),
 967→                        before: None,
 968→                        after: None,
 969→                        first: false, // Append to end to maintain order
 970→                    };
 971→                    jjrg_draft(gallops, draft_args)?;
 972→                }
 973→            }
 974→        }
 975→    }
 976→
 977→    // Update source heat: change silks to garlanded, set status to stabled
 978→    let source_heat_mut = gallops.heats.get_mut(&firemark_key).unwrap();
 979→    source_heat_mut.silks = garlanded_silks.clone();
 980→    source_heat_mut.status = jjrg_HeatStatus::Stabled;
 981→
 982→    // Set new heat status to racing and move to front
 983→    let new_heat_mut = gallops.heats.get_mut(&new_firemark_key).unwrap();
 984→    new_heat_mut.status = jjrg_HeatStatus::Racing;
 985→    if let Some(heat_entry) = gallops.heats.shift_remove(&new_firemark_key) {
 986→        gallops.heats.shift_insert(0, new_firemark_key.clone(), heat_entry);
 987→    }
 988→
 989→    Ok(jjrg_GarlandResult {
 990→        old_firemark: firemark_key,
 991→        old_silks: garlanded_silks,
 992→        new_firemark: new_firemark_key,
 993→        new_silks: continuation_silks,
 994→        paces_transferred: actionable_count,
 995→        paces_retained: retained_count,
 996→    })
 997→}
 998→
 999→/// Restring - bulk draft multiple paces atomically
1000→///
1001→/// Moves multiple paces from source heat to destination heat in a single operation.
1002→/// All paces are validated before any mutations occur.
1003→/// Order is preserved in the destination heat.
1004→pub fn jjrg_restring(gallops: &mut jjrg_Gallops, args: jjrg_RestringArgs) -> Result<jjrg_RestringResult, String> {
1005→    // Parse and normalize firemarks
1006→    let source_firemark = Firemark::jjrf_parse(&args.source_firemark)
1007→        .map_err(|e| format!("Invalid source firemark: {}", e))?;
1008→    let source_firemark_key = source_firemark.jjrf_display();
1009→
1010→    let dest_firemark = Firemark::jjrf_parse(&args.dest_firemark)
1011→        .map_err(|e| format!("Invalid destination firemark: {}", e))?;
1012→    let dest_firemark_key = dest_firemark.jjrf_display();
1013→
1014→    // Validate firemarks are different
1015→    if source_firemark_key == dest_firemark_key {
1016→        return Err("Cannot draft paces to same heat".to_string());
1017→    }
1018→
1019→    // Validate both heats exist
1020→    if !gallops.heats.contains_key(&source_firemark_key) {
1021→        return Err(format!("Heat '{}' not found", source_firemark_key));
1022→    }
1023→    if !gallops.heats.contains_key(&dest_firemark_key) {
1024→        return Err(format!("Heat '{}' not found", dest_firemark_key));
1025→    }
1026→
1027→    // Validate coronet array is non-empty
1028→    if args.coronets.is_empty() {
1029→        return Err("No paces specified for draft".to_string());
1030→    }
1031→
1032→    // Validate all coronets before any mutations
1033→    let mut normalized_coronets = Vec::new();
1034→    for coronet_str in &args.coronets {
1035→        // Parse and normalize coronet
1036→        let coronet = Coronet::jjrf_parse(coronet_str)
1037→            .map_err(|e| format!("Invalid coronet '{}': {}", coronet_str, e))?;
1038→        let coronet_key = coronet.jjrf_display();
1039→
1040→        // Verify coronet belongs to source heat
1041→        let coronet_firemark = coronet.jjrf_parent_firemark();
1042→        if coronet_firemark.jjrf_display() != source_firemark_key {
1043→            return Err(format!(
1044→                "Pace {} does not belong to source heat {}",
1045→                coronet_key, source_firemark_key
1046→            ));
1047→        }
1048→
1049→        // Verify pace exists in source heat
1050→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
1051→        if !source_heat.paces.contains_key(&coronet_key) {
1052→            return Err(format!(
1053→                "Pace {} not found in heat {}",
1054→                coronet_key, source_firemark_key
1055→            ));
1056→        }
1057→
1058→        normalized_coronets.push(coronet_key);
1059→    }
1060→
1061→    // All validations passed - now perform the operations
1062→
1063→    // Capture source heat info before mutations
1064→    let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
1065→    let source_silks = source_heat.silks.clone();
1066→    let source_paddock = source_heat.paddock_file.clone();
1067→
1068→    // Capture destination heat info
1069→    let dest_heat = gallops.heats.get(&dest_firemark_key).unwrap();
1070→    let dest_silks = dest_heat.silks.clone();
1071→    let dest_paddock = dest_heat.paddock_file.clone();
1072→
1073→    // Draft each pace to destination (preserving order)
1074→    let mut mappings = Vec::new();
1075→    for coronet_key in normalized_coronets {
1076→        let draft_args = jjrg_DraftArgs {
1077→            coronet: coronet_key.clone(),
1078→            to: dest_firemark_key.clone(),
1079→            before: None,
1080→            after: None,
1081→            first: false, // Append to end to preserve order
1082→        };
1083→
1084→        // Get pace info before drafting (for output)
1085→        let source_heat = gallops.heats.get(&source_firemark_key).unwrap();
1086→        let pace = source_heat.paces.get(&coronet_key).unwrap();
1087→        let first_tack = pace.tacks.first();
1088→        let silks = first_tack.map(|t| t.silks.clone()).unwrap_or_default();
1089→        let state = first_tack.map(|t| t.state.clone()).unwrap_or(jjrg_PaceState::Rough);
1090→        let spec_full = first_tack.map(|t| t.text.clone()).unwrap_or_default();
1091→        let spec_preview = if spec_full.len() > 80 {
1092→            format!("{}...", &spec_full[..77])
1093→        } else {
1094→            spec_full.clone()
1095→        };
1096→
1097→        // Perform the draft
1098→        let result = jjrg_draft(gallops, draft_args)?;
1099→
1100→        mappings.push(jjrg_RestringMapping {
1101→            old_coronet: coronet_key,
1102→            new_coronet: result.new_coronet,
1103→            silks,
1104→            state,
1105→            spec: spec_preview,
1106→        });
1107→    }
1108→
1109→    // Check if source heat is now empty
1110→    let source_heat_after = gallops.heats.get(&source_firemark_key).unwrap();
1111→    let source_empty_after = source_heat_after.paces.is_empty();
1112→
1113→    Ok(jjrg_RestringResult {
1114→        source_firemark: source_firemark_key,
1115→        source_silks,
1116→        source_paddock,
1117→        source_empty_after,
1118→        dest_firemark: dest_firemark_key,
1119→        dest_silks,
1120→        dest_paddock,
1121→        drafted: mappings,
1122→    })
1123→}
