  5→//! Steeplechase Operations - git history parsing for JJ session tracking
  6→//!
  7→//! Implements jjx_rein: parse git history for steeplechase entries belonging to a Heat.
  8→//! Steeplechase entries are stored in git commit messages, not the Gallops JSON.
  9→//!
 10→//! Commit format: `jjb:HALLMARK:IDENTITY:ACTION: message`
 11→//! - HALLMARK: Version identifier (NNNN or NNNN-xxxxxxx)
 12→//! - IDENTITY: ₢CORONET for pace-level, ₣FIREMARK for heat-level
 13→//! - ACTION: Single letter code (required for all commits)
 14→
 15→use serde::Serialize;
 16→use std::process::Command;
 17→
 18→use crate::jjrf_favor::{jjrf_Firemark as Firemark, JJRF_FIREMARK_PREFIX as FIREMARK_PREFIX, JJRF_CORONET_PREFIX as CORONET_PREFIX};
 19→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
 20→
 21→/// Arguments for jjx_rein command
 22→#[derive(Debug)]
 23→pub struct jjrs_ReinArgs {
 24→    /// Target Heat identity (Firemark, with or without prefix)
 25→    pub firemark: String,
 26→
 27→    /// Maximum entries to return
 28→    pub limit: usize,
 29→}
 30→
 31→/// Steeplechase entry - parsed from git commit message
 32→#[derive(Debug, Clone, Serialize, Default)]
 33→pub struct jjrs_SteeplechaseEntry {
 34→    /// Timestamp in "YYYY-MM-DD HH:MM" format
 35→    pub timestamp: String,
 36→
 37→    /// Abbreviated git commit SHA
 38→    pub commit: String,
 39→
 40→    /// Hallmark version identifier (NNNN or NNNN-xxxxxxx)
 41→    #[serde(skip_serializing_if = "Option::is_none")]
 42→    pub hallmark: Option<String>,
 43→
 44→    /// Coronet for pace-level entries, None for heat-level
 45→    #[serde(skip_serializing_if = "Option::is_none")]
 46→    pub coronet: Option<String>,
 47→
 48→    /// Action code (single letter), 'n' for standard notch commits
 49→    #[serde(skip_serializing_if = "Option::is_none")]
 50→    pub action: Option<String>,
 51→
 52→    /// Commit message or marker description
 53→    pub subject: String,
 54→}
 55→
 56→/// Parse timestamp from git %ai format to "YYYY-MM-DD HH:MM"
 57→/// Input format: "2024-01-15 14:30:00 -0800"
 58→pub(crate) fn zjjrs_parse_timestamp(git_timestamp: &str) -> String {
 59→    let trimmed = git_timestamp.trim();
 60→    if trimmed.len() >= 16 {
 61→        trimmed[..16].to_string()
 62→    } else {
 63→        trimmed.to_string()
 64→    }
 65→}
 66→
 67→/// Parse commit format: jjb:HALLMARK:IDENTITY:ACTION: message
 68→/// Filters by firemark identity.
 69→pub fn zjjrs_parse_new_format(subject: &str, firemark_raw: &str) -> Option<jjrs_SteeplechaseEntry> {
 70→    // Expected format: jjb:HALLMARK:IDENTITY:ACTION: message
 71→    if !subject.starts_with("jjb:") {
 72→        return None;
 73→    }
 74→
 75→    // Skip past "jjb:" to get hallmark
 76→    let after_jjb = &subject[4..]; // skip "jjb:"
 77→
 78→    // Parse hallmark (required) - find next colon
 79→    let hallmark_end = after_jjb.find(':')?;
 80→    let hallmark_str = &after_jjb[..hallmark_end];
 81→    let hallmark = Some(hallmark_str.to_string());
 82→    let after_hallmark = &after_jjb[hallmark_end + 1..];
 83→
 84→    // Parse identity (₢CORONET or ₣FIREMARK)
 85→    let (identity, rest) = if after_hallmark.starts_with(CORONET_PREFIX) {
 86→        // Coronet: ₢XXXXX (1 prefix char + 5 base64 chars = 6 chars total in UTF-8)
 87→        let coronet_end = CORONET_PREFIX.len_utf8() + 5;
 88→        if after_hallmark.len() < coronet_end {
 89→            return None;
 90→        }
 91→        let coronet = &after_hallmark[..coronet_end];
 92→        // Verify this coronet belongs to our heat (first 2 chars of base64 match firemark)
 93→        let coronet_heat = &after_hallmark[CORONET_PREFIX.len_utf8()..CORONET_PREFIX.len_utf8() + 2];
 94→        if coronet_heat != firemark_raw {
 95→            return None;
 96→        }
 97→        (Some(coronet.to_string()), &after_hallmark[coronet_end..])
 98→    } else if after_hallmark.starts_with(FIREMARK_PREFIX) {
 99→        // Firemark: ₣XX (1 prefix char + 2 base64 chars)
100→        let firemark_end = FIREMARK_PREFIX.len_utf8() + 2;
101→        if after_hallmark.len() < firemark_end {
102→            return None;
103→        }
104→        // Verify this is our firemark
105→        let fm = &after_hallmark[FIREMARK_PREFIX.len_utf8()..firemark_end];
106→        if fm != firemark_raw {
107→            return None;
108→        }
109→        (None, &after_hallmark[firemark_end..])
110→    } else {
111→        return None;
112→    };
113→
114→    // Now parse: [:ACTION]: message
115→    // rest should start with either ": " (no action) or ":X: " (with action)
116→    if !rest.starts_with(':') {
117→        return None;
118→    }
119→
120→    let after_colon = &rest[1..];
121→
122→    let (action, message) = if after_colon.starts_with(' ') {
123→        // No action code, just ": message"
124→        (None, after_colon[1..].to_string())
125→    } else {
126→        // Has action code: "X: message"
127→        // Find the next colon
128→        if let Some(colon_pos) = after_colon.find(':') {
129→            let action_code = &after_colon[..colon_pos];
130→            let msg = after_colon[colon_pos + 1..].trim_start().to_string();
131→            (Some(action_code.to_string()), msg)
132→        } else {
133→            return None;
134→        }
135→    };
136→
137→    Some(jjrs_SteeplechaseEntry {
138→        timestamp: String::new(), // filled by caller
139→        commit: String::new(),    // filled by caller
140→        hallmark,
141→        coronet: identity,
142→        action,
143→        subject: message,
144→    })
145→}
146→
147→/// Parse a single git log line into a SteeplechaseEntry
148→/// Line format: "YYYY-MM-DD HH:MM:SS -ZZZZ<TAB>abbrev_commit<TAB>subject"
149→pub fn zjjrs_parse_log_line(line: &str, firemark_raw: &str) -> Option<jjrs_SteeplechaseEntry> {
150→    let parts: Vec<&str> = line.splitn(3, '\t').collect();
